#!/bin/sh
# End-to-end parity check: lint a real Ruby tree with oxidecop AND real
# rubocop (restricted to the cops oxidecop implements), then diff the
# normalized offense lists. This is the acceptance test for the project's
# actual selling point — same offenses on real code, not just on spec
# fixtures. Exit 0 = byte-identical offense sets.
#
#   tools/parity.sh <ruby-source-dir>
#   tools/parity.sh "$(dirname "$(gem which rubocop)")/rubocop"   # rubocop's own source
set -e
ROOT=$(cd "$(dirname "$0")/.." && pwd)
TARGET=${1:?usage: parity.sh <ruby-source-dir>}
[ -d "$TARGET" ] || { echo "not a directory: $TARGET" >&2; exit 2; }
BIN="$ROOT/target/release/oxidecop"
WORK=$(mktemp -d)
trap 'rm -rf "$WORK"' EXIT

# Keep in sync with oracle/leaderboard.rb COPS (the implemented set).
COPS="Style/NilComparison,Style/NumericPredicate,Style/ZeroLengthPredicate,Style/RedundantReturn,Style/NumericLiterals,Style/StringLiterals,Style/Documentation,Style/FrozenStringLiteralComment,Style/SymbolProc,Naming/MethodName,Lint/NestedMethodDefinition,Layout/LineLength,Layout/TrailingWhitespace,Style/EvenOdd,Lint/RandOne,Style/ArrayJoin,Lint/BooleanSymbol,Lint/BigDecimalNew,Style/Dir,Style/StringChars,Style/NestedFileDirname,Lint/UriRegexp,Lint/UnifiedInteger,Lint/EmptyEnsure,Lint/EmptyExpression,Lint/UriEscapeUnescape,Style/UnpackFirst,Style/RandomWithOffset,Lint/Debugger,Style/NegatedIf,Lint/EmptyFile,Layout/TrailingEmptyLines,Layout/InitialIndentation,Style/NegatedWhile,Style/CharacterLiteral,Style/UnlessElse,Lint/EmptyInterpolation,Lint/EnsureReturn,Style/EndBlock,Style/BeginBlock,Naming/ConstantName,Naming/ClassAndModuleCamelCase,Naming/BinaryOperatorParameterName,Lint/DuplicateRequire,Style/StderrPuts,Style/WhileUntilDo,Style/MultilineIfThen,Style/Not,Style/ColonMethodCall,Lint/EmptyClass,Lint/DeprecatedClassMethods,Layout/EmptyLineAfterMagicComment,Layout/EmptyLines,Style/EmptyLiteral,Style/Semicolon,Style/GlobalVars,Layout/SpaceAfterComma,Layout/SpaceBeforeSemicolon,Style/DefWithParentheses,Layout/SpaceBeforeComma,Layout/SpaceBeforeComment,Lint/FloatOutOfRange,Style/SymbolLiteral,Lint/RescueException,Style/WhenThen,Lint/DuplicateHashKey,Security/MarshalLoad,Layout/SpaceAfterMethodName,Layout/SpaceAfterSemicolon,Layout/SpaceAfterNot,Lint/UnifiedInteger,Lint/FlipFlop,Style/Proc,Lint/DuplicateCaseCondition,Lint/DuplicateElsifCondition,Style/ColonMethodDefinition,Layout/LeadingEmptyLines,Style/Strip,Lint/TopLevelReturnWithArgument,Security/Eval,Style/VariableInterpolation,Lint/EachWithObjectArgument,Style/TrailingBodyOnModule,Lint/RegexpAsCondition,Lint/DuplicateRescueException,Style/TrailingBodyOnClass,Lint/SafeNavigationWithEmpty,Style/RedundantCapitalW,Lint/HashCompareByIdentity,Lint/NextWithoutAccumulator,Layout/SpaceAfterColon,Lint/MultipleComparison,Style/EmptyLambdaParameter,Layout/SpaceInsideArrayPercentLiteral,Style/IfUnlessModifierOfIfUnless,Style/EmptyBlockParameter,Lint/IdentityComparison,Layout/SpaceInsideRangeLiteral,Style/DoubleCopDisableDirective,Style/ClassCheck,Naming/BlockParameterName,Style/ClassMethods,Style/TrailingBodyOnMethodDefinition,Lint/UselessElseWithoutRescue,Lint/ReturnInVoidContext,Style/MultilineBlockChain,Style/OptionalArguments,Style/RedundantFileExtensionInRequire,Lint/TrailingCommaInAttributeDeclaration,Layout/ConditionPosition,Naming/HeredocDelimiterNaming,Style/MultilineWhenThen,Naming/MethodParameterName,Style/MultilineIfModifier,Layout/EmptyLinesAroundBeginBody,Layout/EmptyLinesAroundBlockBody,Style/ClassVars,Lint/NestedPercentLiteral,Lint/PercentSymbolArray,Style/MinMax,Style/TrailingMethodEndStatement,Style/OptionalBooleanParameter,Layout/SpaceInsideStringInterpolation,Layout/EmptyLinesAroundMethodBody,Style/NestedTernaryOperator,Layout/AssignmentIndentation,Lint/CircularArgumentReference,Lint/BinaryOperatorWithIdenticalOperands,Lint/InterpolationCheck,Lint/FloatComparison,Layout/SpaceInsidePercentLiteralDelimiters,Lint/EmptyWhen,Lint/InheritException,Lint/ConstantDefinitionInBlock,Lint/ElseLayout,Layout/EmptyLinesAroundModuleBody,Lint/DisjunctiveAssignmentInConstructor,Lint/IneffectiveAccessModifier,Layout/LeadingCommentSpace,Lint/DeprecatedOpenSSLConstant,Lint/AssignmentInCondition,Layout/EmptyLinesAroundClassBody,Lint/AmbiguousRegexpLiteral,Layout/BlockEndNewline,Metrics/CyclomaticComplexity,Metrics/PerceivedComplexity,Metrics/AbcSize,Layout/EmptyLinesAroundAttributeAccessor,Style/RedundantSortBy,Layout/SpaceInLambdaLiteral,Layout/SpaceAroundEqualsInParameterDefault,Layout/EndOfLine,Lint/AmbiguousBlockAssociation,Lint/AmbiguousOperator,Layout/EmptyLinesAroundExceptionHandlingKeywords,Style/RedundantPercentQ,Layout/SpaceBeforeFirstArg,Lint/UnreachableCode,Lint/RedundantStringCoercion,Style/EachForSimpleLoop,Lint/RedundantWithIndex,Layout/CommentIndentation,Layout/DotPosition,Lint/UselessSetterCall,Lint/EmptyConditionalBody,Style/ComparableClamp,Style/RedundantFreeze,Lint/LiteralInInterpolation,Lint/EmptyBlock,Lint/DuplicateMagicComment,Style/NilLambda,Lint/UselessMethodDefinition,Lint/SelfAssignment,Layout/AccessModifierIndentation,Layout/CaseIndentation,Style/RedundantSelf,Lint/UselessTimes,Layout/EmptyLinesAroundAccessModifier,Lint/ToJSON,Security/YAMLLoad,Style/StabbyLambdaParentheses,Lint/StructNewOverride,Lint/Loop,Style/BlockComments,Layout/BeginEndAlignment,Style/GlobalStdStream,Style/EmptyElse,Layout/EmptyLineBetweenDefs,Style/SelfAssignment,Style/SingleLineMethods,Style/PreferredHashMethods,Style/NumericLiteralPrefix,Security/Open,Security/JSONLoad,Style/Sample,Style/Attr,Style/MissingRespondToMissing,Style/HashLikeCase,Style/PercentQLiterals,Lint/PercentStringArray,Lint/MixedRegexpCaptureTypes,Style/NestedParenthesizedCalls,Style/StringLiteralsInInterpolation,Style/BarePercentLiterals,Lint/RequireParentheses,Style/CaseEquality,Style/RedundantException,Naming/AsciiIdentifiers,Lint/ErbNewArguments,Lint/OrderedMagicComments,Style/NestedModifier,Layout/MultilineArrayBraceLayout,Layout/MultilineHashBraceLayout,Layout/MultilineMethodDefinitionBraceLayout,Layout/DefEndAlignment,Style/WhileUntilModifier,Style/ExponentialNotation,Style/StructInheritance,Style/ExpandPathArguments,Style/RedundantSelfAssignment,Style/ModuleFunction,Style/SingleArgumentDig,Style/Encoding,Style/RedundantFetchBlock,Metrics/ParameterLists,Layout/ClosingHeredocIndentation,Lint/ImplicitStringConcatenation,Style/KeywordParametersOrder,Naming/AccessorMethodName,Style/PerlBackrefs,Lint/RaiseException,Lint/RedundantWithObject,Style/RedundantConditional,Style/MultilineMemoization,Style/NegatedUnless,Style/NonNilCheck,Style/MixinUsage,Lint/UnderscorePrefixedVariableName,Lint/MissingCopEnableDirective,Layout/MultilineMethodCallBraceLayout,Style/LambdaCall,Naming/HeredocDelimiterCase,Lint/RescueType,Style/CommentAnnotation,Lint/SuppressedException,Style/TrailingUnderscoreVariable,Lint/NonLocalExitFromIterator,Layout/EmptyComment,Style/EmptyCaseCondition,Style/OneLineConditional,Style/IfWithSemicolon,Style/MultilineTernaryOperator,Style/CommentedKeyword,Style/For,Style/RedundantSort,Style/FloatDivision,Style/EachWithObject,Style/CaseLikeIf,Naming/VariableName,Naming/RescuedExceptionsVariableName,Lint/UnreachableLoop,Style/InfiniteLoop,Style/OrAssignment,Style/EmptyMethod,Lint/RedundantRequireStatement,Lint/SendWithMixinArgument,Style/HashAsLastArrayItem,Lint/ParenthesesAsGroupedExpression,Naming/PredicatePrefix,Bundler/InsecureProtocolSource,Bundler/DuplicatedGem,Bundler/GemFilename,Gemspec/RubyVersionGlobalsUsage,Gemspec/DuplicatedAssignment,Gemspec/RequiredRubyVersion,Gemspec/OrderedDependencies,Layout/IndentationStyle,Layout/ParameterAlignment,Style/RedundantAssignment,Bundler/OrderedGems,Layout/SpaceBeforeBlockBraces,Lint/MissingSuper,Style/LineEndConcatenation,Style/CombinableLoops,Style/SlicingWithRange,Style/RedundantInterpolation,Style/BisectedAttrAccessor,Layout/SpaceAroundKeyword,Style/MixinGrouping,Style/ClassEqualityComparison,Style/ParenthesesAroundCondition,Layout/SpaceInsideParens,Style/ExplicitBlockArgument,Style/RescueModifier,Layout/FirstParameterIndentation,Bundler/DuplicatedGroup,Layout/EmptyLinesAroundArguments,Style/EvalWithLocation,Style/MethodCallWithoutArgsParentheses,Style/Alias,Style/RaiseArgs,Style/MethodDefParentheses,Lint/SafeNavigationConsistency,Style/HashTransformKeys,Style/SymbolArray,Style/HashTransformValues,Layout/ArrayAlignment,Lint/RedundantCopEnableDirective,Style/TrailingCommaInHashLiteral,Metrics/ModuleLength,Style/SpecialGlobalVars,Style/StringConcatenation,Metrics/BlockLength,Metrics/ClassLength,Lint/NonDeterministicRequireOrder,Metrics/BlockNesting,Lint/FormatParameterMismatch,Style/TrailingCommaInArrayLiteral,Metrics/MethodLength,Layout/SpaceAroundMethodCallOperator,Style/WordArray,Layout/SpaceAroundBlockParameters,Style/TrailingCommaInArguments,Layout/HeredocIndentation,Style/RescueStandardError,Naming/MemoizedInstanceVariableName,Lint/OutOfRangeRegexpRef,Style/PercentLiteralDelimiters,Lint/RedundantSplatExpansion,Style/DoubleNegation,Naming/VariableNumber,Style/CommandLiteral,Style/AccessorGrouping,Style/IfInsideElse,Style/AndOr,Style/IdenticalConditionalBranches,Style/YodaCondition,Style/TernaryParentheses,Style/SignalException,Style/RedundantBegin,Style/SoleNestedConditional,Style/Next,Style/RegexpLiteral,Lint/ShadowedException,Lint/SafeNavigationChain,Style/MultipleComparison,Style/TrivialAccessors,Naming/FileName,Style/Lambda,Style/GuardClause,Lint/LiteralAsCondition,Lint/ShadowedArgument,Lint/Void,Style/HashSyntax,Lint/UnusedBlockArgument,Lint/UnusedMethodArgument,Lint/UselessAccessModifier,Style/HashEachMethods,Style/MutableConstant,Style/InverseMethods,Style/RedundantCondition,Lint/RedundantSafeNavigation,Style/ClassAndModuleChildren,Lint/DuplicateMethods,Lint/UselessAssignment,Style/IfUnlessModifier,Style/FormatString,Style/FormatStringToken,Style/ConditionalAssignment,Style/AccessModifierDeclarations,Style/BlockDelimiters,Style/RedundantParentheses,Layout/SpaceInsideHashLiteralBraces,Layout/SpaceInsideReferenceBrackets,Layout/SpaceInsideBlockBraces,Layout/SpaceInsideArrayLiteralBrackets,Layout/EmptyLineAfterGuardClause,Layout/ExtraSpacing"

cargo build --release --manifest-path "$ROOT/Cargo.toml" --quiet

# Normalize both outputs to "file:line:col: Cop: message" (headers folded in,
# [Correctable] tags stripped, absolute paths trimmed to the target-relative).
# Backticks go too: rubocop's simple formatter renders `...` spans as colored
# text (stripping the backticks under --no-color) — presentation, not message.
normalize() {
  awk -v strip="$1" '
    /^== .* ==$/ { f = substr($0, 4, length($0) - 6); sub(strip, "", f); next }
    /^[A-Z]:/ {
      line = $0
      sub(/^[A-Z]: */, "", line)
      gsub(/\[Correctable\] /, "", line)
      gsub(/`/, "", line)
      printf "%s:%s\n", f, line
    }
  ' | sort
}

# A corpus whose config `plugins:`-requires gems we don't install carries a
# cleaned copy (.rubocop_bench.yml); both sides must use the same one.
CFG=".rubocop.yml"
[ -f "$TARGET/.rubocop_bench.yml" ] && CFG=".rubocop_bench.yml"
# Both sides get --only: rubocop force-enables the listed cops (even under
# DisabledByDefault configs like rails'), so ours must too.
(cd "$TARGET" && "$BIN" --only "$COPS" . "$CFG") | normalize "^\./" > "$WORK/ours.txt" || true
(cd "$TARGET" && rubocop -c "$CFG" --only "$COPS" --cache false -f simple --no-color . 2>/dev/null) \
  | normalize "^\./" > "$WORK/theirs.txt" || true

if diff -u "$WORK/theirs.txt" "$WORK/ours.txt"; then
  echo "PARITY: $(wc -l < "$WORK/ours.txt" | tr -d ' ') offense lines identical on $TARGET"
else
  echo "DIVERGED (see diff above; - = rubocop only, + = oxidecop only)" >&2
  exit 1
fi
